6631   if (const auto *A = dyn_cast<Argument>(V)) {
6632     if (A->hasAttribute(Attribute::NoUndef) ||
6633         A->hasAttribute(Attribute::Dereferenceable) ||
6634         A->hasAttribute(Attribute::DereferenceableOrNull))
