6641 
6642     if (isa<ConstantInt>(C) || isa<GlobalVariable>(C) || isa<ConstantFP>(V) ||
6643         isa<ConstantPointerNull>(C) || isa<Function>(C))
6644       return true;
6645 
6646     if (C->getType()->isVectorTy() && !isa<ConstantExpr>(C))
6647       return (PoisonOnly ? !C->containsPoisonElement()
6648                          : !C->containsUndefOrPoisonElement()) &&
6649              !C->containsConstantExpression();
6650   }
6651 
6652   // Strip cast operations from a pointer value.
6653   // Note that stripPointerCastsSameRepresentation can strip off getelementptr
6654   // inbounds with zero offset. To guarantee that the result isn't poison, the
6655   // stripped pointer is checked as it has to be pointing into an allocated
6656   // object or be null `null` to ensure `inbounds` getelement pointers with a
6657   // zero offset could not produce poison.
6658   // It can strip off addrspacecast that do not change bit representation as
6659   // well. We believe that such addrspacecast is equivalent to no-op.
6660   auto *StrippedV = V->stripPointerCastsSameRepresentation();
6661   if (isa<AllocaInst>(StrippedV) || isa<GlobalVariable>(StrippedV) ||
6662       isa<Function>(StrippedV) || isa<ConstantPointerNull>(StrippedV))
6663     return true;
6664 
6665   auto OpCheck = [&](const Value *V) {
6666     return isGuaranteedNotToBeUndefOrPoison(V, AC, CtxI, DT, Depth + 1,
6667                                             PoisonOnly);
6668   };
6669 
6670   if (auto *Opr = dyn_cast<Operator>(V)) {
6671     // If the value is a freeze instruction, then it can never
6672     // be undef or poison.
6673     if (isa<FreezeInst>(V))
6674       return true;
6675 
6676     if (const auto *CB = dyn_cast<CallBase>(V)) {
6677       if (CB->hasRetAttr(Attribute::NoUndef))
6678         return true;
6679     }
6680 
6681     if (const auto *PN = dyn_cast<PHINode>(V)) {
6682       unsigned Num = PN->getNumIncomingValues();
6683       bool IsWellDefined = true;
6684       for (unsigned i = 0; i < Num; ++i) {
6685         auto *TI = PN->getIncomingBlock(i)->getTerminator();
6686         if (!isGuaranteedNotToBeUndefOrPoison(PN->getIncomingValue(i), AC, TI,
6687                                               DT, Depth + 1, PoisonOnly)) {
6688           IsWellDefined = false;
6689           break;
6690         }
6691       }
6692       if (IsWellDefined)
6693         return true;
6694     } else if (!canCreateUndefOrPoison(Opr) && all_of(Opr->operands(), OpCheck))
6695       return true;
6696   }
6697 
6698   if (auto *I = dyn_cast<LoadInst>(V))
6699     if (I->hasMetadata(LLVMContext::MD_noundef) ||
6700         I->hasMetadata(LLVMContext::MD_dereferenceable) ||
6701         I->hasMetadata(LLVMContext::MD_dereferenceable_or_null))
6702       return true;
6703 
6704   if (programUndefinedIfUndefOrPoison(V, PoisonOnly))
6705     return true;
6706 
6707   // CxtI may be null or a cloned instruction.
6708   if (!CtxI || !CtxI->getParent() || !DT)
6709     return false;
6710 
6711   auto *DNode = DT->getNode(CtxI->getParent());
6712   if (!DNode)
6713     // Unreachable block
6714     return false;
6715 
6716   // If V is used as a branch condition before reaching CtxI, V cannot be
6717   // undef or poison.
6718   //   br V, BB1, BB2
6719   // BB1:
6720   //   CtxI ; V cannot be undef or poison here
6721   auto *Dominator = DNode->getIDom();
6722   while (Dominator) {
6723     auto *TI = Dominator->getBlock()->getTerminator();
6724 
6725     Value *Cond = nullptr;
6726     if (auto BI = dyn_cast_or_null<BranchInst>(TI)) {
6727       if (BI->isConditional())
6728         Cond = BI->getCondition();
6729     } else if (auto SI = dyn_cast_or_null<SwitchInst>(TI)) {
6730       Cond = SI->getCondition();
6731     }
6732 
6733     if (Cond) {
6734       if (Cond == V)
6735         return true;
6736       else if (PoisonOnly && isa<Operator>(Cond)) {
6737         // For poison, we can analyze further
6738         auto *Opr = cast<Operator>(Cond);
6739         if (any_of(Opr->operands(),
6740                    [V](const Use &U) { return V == U && propagatesPoison(U); }))
6741           return true;
6742       }
6743     }
6744 
6745     Dominator = Dominator->getIDom();
6746   }
6747 
6748   if (getKnowledgeValidInContext(V, {Attribute::NoUndef}, CtxI, DT, AC))
6749     return true;
6750 
6751   return false;
6752 }
